UPDATE public_vocabulary_entries
SET audio_url = #{audioUrl}
WHERE id = #{entryId}

UPDATE public_vocabulary_entries
SET phonetic = #{phonetic},
    meaning_cn = #{meaningCn},
    example_sentence = #{exampleSentence}
WHERE id = #{id}

UPDATE user_vocabulary_entries
SET phonetic = #{phonetic},
    meaning_cn = #{meaningCn},
    example_sentence = #{exampleSentence},
    category = #{category}
WHERE id = #{id}
